use std::collections::HashMap;

struct AppConfig {
    owner_name: String,
    version: u32,
}

struct FeatureFlags {
    enabled: bool,
    timeout_ms: u64,
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let mut settings: HashMap<&str, Box<dyn std::any::Any>> = HashMap::new();

    let owner = AppConfig {
        owner_name: String::from("ServiceUser"),
        version: 102,
    };
    settings.insert("config", Box::new(owner));

    let features = FeatureFlags {
        enabled: true,
        timeout_ms: 5000,
    };
    settings.insert("features", Box::new(features));

    if let Some(boxed_config) = settings.get("config") {
        let config_ref: &AppConfig = unsafe { &*(std::ptr::addr_of!(**boxed_config).cast::<AppConfig>()) };
        println!("Loaded Config Owner: {}", config_ref.owner_name);
    }

    if let Some(boxed_features) = settings.get("features") {
        let features_ref: &FeatureFlags = unsafe { &*(std::ptr::addr_of!(**boxed_features).cast::<FeatureFlags>()) };
        println!("Loaded Feature Timeout: {}ms", features_ref.timeout_ms);
    }

    Ok(())
}

use std::collections::HashMap;

struct PageData {
    title: String,
    content_parts: Vec<Box<dyn std::any::Any + Send>>,
}

fn main() {
    let mut page1 = PageData {
        title: "About Us".to_string(),
        content_parts: vec![Box::new("Welcome to our site!".to_string()), Box::new(42i32),
        ],
    };

    let page2 = PageData {
        title: "Contact".to_string(),
        content_parts: vec![Box::new("Email us at info@example.com".to_string()), Box::new(true),
        ],
    };

    let combined_pages: Vec<PageData> = vec![page1, page2].into_iter().collect();

    for page in &combined_pages {
        println!("Processing Page: {}", page.title);
        for item_box in &page.content_parts {
            if let Some(s) = item_box.downcast_ref::<String>() {
                println!("  Found String: {}", s);
            }
            if let Some(i) = item_box.downcast_ref::<i32>() {
                println!("  Found Number: {}", i);
            }
            if let Some(b) = item_box.downcast_ref::<bool>() {
                println!("  Found Boolean: {}", b);
            }
        }
    }
}

use std::collections::HashMap;

struct UserContext {
	user_id: u64,
	settings: HashMap<String, String>,
}

struct ApiError {
	message: String,
	status_code: u16,
}

fn process_api_request(
	context: UserContext,
	payload: &str,
	expiry: std::time::Duration
) -> Result<(), (ApiError, std::time::Instant)> {
	let start = std::time::Instant::now();
	println!("Processing request for user {}", context.user_id);
	println!("Using settings: {:?}", context.settings);
	println!("Request expires in {:?}", expiry);
	if payload.is_empty() {
		return Err((ApiError { message: "Payload cannot be empty".to_string(), status_code: 400 }, start));
	}
	println!("Successfully processed payload.");
	Ok(())
}

use std::collections::HashMap;

struct ProcessInfo {
    pid: u32,
    name: String,
    priority: i32,
}

fn main() {
    let mut process_map: HashMap<u32, ProcessInfo> = HashMap::new();

    process_map.insert(100, ProcessInfo { pid: 100, name: String::from("systemd"), priority: 50 });
    process_map.insert(2048, ProcessInfo { pid: 2048, name: String::from("web"), priority: 30 });
    process_map.insert(3100, ProcessInfo { pid: 3100, name: String::from("debugger"), priority: 75 });

    let mut pids_to_check = vec![100, 2048];

    for pid in pids_to_check.iter().cloned() {
        if let Some(info) = process_map.get(&pid) {
            println!("Found process: PID {} Name: {} Priority: {}", info.pid, info.name, info.priority);
        }
    }

    let target_pid = 3100;
    if let Some(info) = process_map.get(&target_pid) {
        println!("!!! SIMULATING KILL !!!nProcess {} is flagged for termination.", info.pid);
        process_map.remove(&target_pid);
    }

    println!("Remaining processes after check: {}", process_map.len());
}

use std::collections::VecDeque;

struct GameStateRecord {
    tick_count: u64,
    joystick_x: i32,
    temperature: f32,
    is_running: bool,
}

fn record_game_state(record: &mut VecDeque<GameStateRecord>, tick: u64, x: i32, temp: f32, active: bool) {
    let new_record = GameStateRecord {
        tick_count: tick,
        joystick_x: x,
        temperature: temp,
        is_running: active,
    };
    record.push_back(new_record);
}

fn process_playback(records: &VecDeque<GameStateRecord>) {
    if records.is_empty() {
        println!("No state records available for playback.");
        return;
    }

    println!("Starting playback simulation...");

    for (index, record) in records.iter().enumerate() {
        if index % 10 == 0 || index == records.len() - 1 {
            println!("n--- Tick {} / {} ---", record.tick_count, records.len() - 1);
            println!("  Joystick X Register: 0x{:X} (Raw Value)", record.joystick_x); 
            println!("  Temperature Sensor Output: {:.2} F", record.temperature);
            println!("  System Active Flag: {}", record.is_running);
        }
    }
    println!("Playback complete.");
}

fn main() {
    let mut history_buffer: VecDeque<GameStateRecord> = VecDeque::new();

    record_game_state(&mut history_buffer, 100, 50, 22.5, true);
    record_game_state(&mut history_buffer, 110, -12, 23.1, true);
    for i in 120..149 { 
        record_game_state(&mut history_buffer, i as u64, (i % 5) * 10 - 25, 23.0 + (i as f32 / 100.0), true);
    }
    record_game_state(&mut history_buffer, 150, 0, 22.9, false); 

    process_playback(&history_buffer);
}
